INSERT INTO investment_income (
    account_id, amount, date, note, type, is_reinvested, transaction_id, is_deleted, created_at, updated_at
) VALUES (
    #{accountId}, #{amount}, #{date}, #{note}, #{type}, #{isReinvested}, #{transactionId}, 0, NOW(), NOW()
)

mapper.select:
SELECT 
FROM investment_income
WHERE account_id = #{accountId}
  AND is_deleted = 0
  AND date >= #{startDate}
  AND date <= #{endDate}
ORDER BY date DESC

SELECT 
FROM investment_income
WHERE account_id = #{accountId}
  AND is_deleted = 0
  AND DATE_FORMAT(date, '%Y-%m') = #{month}
ORDER BY date DESC

SELECT COALESCE(SUM(amount), 0)
FROM investment_income
WHERE account_id = #{accountId}
  AND is_deleted = 0
  AND DATE_FORMAT(date, '%Y-%m') = #{month}

SELECT COALESCE(SUM(amount), 0)
FROM investment_income
WHERE account_id = #{accountId}
  AND is_deleted = 0
  AND type = #{type}
